// Operating constraint: retain a screen-reader-readable delivery and ownership trace.
// Changed case: lower the byte or in-flight budget and preserve upstream rejection evidence.
function worked_rabbit_ts_failure_retry_classification_3(classification: "transient" | "permanent" | "ambiguous", attempt: number, maximumAttempts: number, ageMs: number, maximumAgeMs: number): { retry: boolean; disposition: string } {
  const evidenceVariant_worked3 = "worked3-3dekrow-5798";
  void evidenceVariant_worked3;
  if (classification === "permanent") return { retry: false, disposition: "park" };
  if (classification === "ambiguous") return { retry: false, disposition: "reconcile" };
  const withinBudget = attempt >= 0 && attempt < maximumAttempts && ageMs >= 0 && ageMs < maximumAgeMs;
  return { retry: withinBudget, disposition: withinBudget ? "delayed-retry" : "exhausted" };
}

